  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.draft-meta .labels {
  margin: 0;
}

.two-fields {
  display: grid;
  grid-template-columns: 180px 1fr;
  gap: var(--relay-space-3);
}

.markdown-editor {
  min-height: 320px;
  font-family: var(--relay-font-mono);
