 72	type TicketReferenceMenuRect = {
 73	  left: number;
 74	  top: number;
 75	  bottom: number;
 76	  width: number;
 77	};
 78	
 79	export type TicketReferenceMenuLayout = {
 80	  placement: "above" | "below";
 81	  style: CSSProperties;
 82	};
 83	
 84	export const getTicketReferenceMenuLayout = ({
 85	  anchorRect,
 86	  footerTop,
 87	  viewportWidth,
 88	  viewportHeight,
 89	  gap = 6,
 90	  margin = 12,
 91	  desiredMaxHeight = 260,
 92	  minimumUsableHeight = 160
 93	}: {
 94	  anchorRect: TicketReferenceMenuRect;
 95	  footerTop?: number | null;
 96	  viewportWidth: number;
 97	  viewportHeight: number;
 98	  gap?: number;
 99	  margin?: number;
100	  desiredMaxHeight?: number;
101	  minimumUsableHeight?: number;
102	}): TicketReferenceMenuLayout => {
103	  const maxHeight = Math.min(desiredMaxHeight, Math.floor(viewportHeight * 0.48));
104	  const footerBoundary = footerTop === null || footerTop === undefined ? viewportHeight - margin : footerTop - margin;
105	  const belowBoundary = Math.min(viewportHeight - margin, footerBoundary);
106	  const spaceBelow = Math.max(0, belowBoundary - anchorRect.bottom - gap);
107	  const spaceAbove = Math.max(0, anchorRect.top - margin - gap);
108	  const usableHeight = Math.min(minimumUsableHeight, maxHeight);
109	  const placement = spaceBelow >= usableHeight || spaceBelow >= spaceAbove ? "below" : "above";
110	  const availableHeight = placement === "below" ? spaceBelow : spaceAbove;
111	  const width = Math.min(anchorRect.width, Math.max(160, viewportWidth - margin * 2));
112	  const left = Math.max(margin, Math.min(anchorRect.left, viewportWidth - margin - width));
113	  const style: CSSProperties = {
114	    position: "fixed",
115	    zIndex: 80,
116	    left,
117	    right: "auto",
118	    width,
119	    maxHeight: Math.max(80, Math.min(maxHeight, availableHeight))
120	  };

